package com.pos;
import javax.swing.*; import java.awt.*;
public class ReturnRefundPanel extends JPanel { private final UserSession s; private final QueryTableModel m=new QueryTableModel(); private final JTable t=new JTable(m); private final JTextField order=new JTextField(6),customer=new JTextField("0",5),product=new JTextField(6),qty=new JTextField("1",5),reason=new JTextField(20);
 public ReturnRefundPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("Returns and Refunds"),BorderLayout.WEST);JButton refresh=new JButton("Refresh");h.add(refresh,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel f=new JPanel();f.setBorder(BorderFactory.createTitledBorder("Complete Return and Restock"));f.add(new JLabel("Order ID"));f.add(order);f.add(new JLabel("Customer ID / 0 walk-in"));f.add(customer);f.add(new JLabel("Product ID"));f.add(product);f.add(new JLabel("Qty"));f.add(qty);f.add(new JLabel("Reason"));f.add(reason);JButton approve=new JButton("Approve Selected Pending Return"),post=new JButton("Direct Walk-in Return & Refund");f.add(approve);f.add(post);add(f,BorderLayout.SOUTH);refresh.addActionListener(e->load());approve.addActionListener(e->approve());post.addActionListener(e->post());load();}
 private void load(){try{m.load("SELECT r.return_id,r.return_no,r.order_id,r.return_date,r.reason,r.status,r.total_refund,f.refund_no,f.amount,f.status refund_status FROM sales_returns r LEFT JOIN refunds f ON f.return_id=r.return_id ORDER BY r.return_id DESC");}catch(Exception e){UIUtils.error(this,e);}}
 private void approve(){int r=t.getSelectedRow();if(r<0)return;try{int id=Integer.parseInt(String.valueOf(t.getValueAt(t.convertRowIndexToModel(r),0)));POSService.approvePendingReturn(id,s.userId);Audit.log(s,"APPROVE_RETURN","return_id="+id);load();UIUtils.info(this,"Pending return approved, stock restored and refund released.");}catch(Exception e){UIUtils.error(this,e);}}
 private void post(){try{POSService.processReturn(Integer.parseInt(order.getText()),Integer.parseInt(customer.getText()),Integer.parseInt(product.getText()),Double.parseDouble(qty.getText()),reason.getText(),s.userId);Audit.log(s,"POST_RETURN","order="+order.getText());load();UIUtils.info(this,"Return restocked and refund released.");}catch(Exception e){UIUtils.error(this,e);}}
}
